# Guild System
import json

class Member:
    def __init__(self, name, rank):
        self.name = name
        self.rank = rank
        self.xp = 0

    def promote(self):
        self.rank += 1

class Guild:
    def __init__(self, name):
        self.name = name
        self.members = []
        self.treasury = 0

    def recruit(self, name):
        m = Member(name, rank=1)
        self.members.append(m)
        return m

    def deposit(self, amount):
        self.treasury += amount

    def top_members(self, n=5):
        ranked = sorted(
            self.members,
            key=lambda m: m.xp,
            reverse=True
        )
        return ranked[:n]

    def save(self, path):
        data = {
            'name': self.name,
            'treasury': self.treasury,
            'members': len(self.members)
        }
        with open(path, 'w') as f:
            json.dump(data, f)
